var lemonadeChange = function(bills) {
    let fives = 0, tens = 0;
    for (const b of bills) {
        if (b === 5) {
            fives++;
        } else if (b === 10) {
            if (fives === 0) return false;
            fives--; tens++;
        } else {
            if (tens > 0 && fives > 0) { tens--; fives--; }
            else if (fives >= 3) { fives -= 3; }
            else return false;
        }
    }
    return true;
};
